// Verify webhook signature
const crypto = require('crypto');
const webhookSecret = $env.RAZORPAY_WEBHOOK_SECRET;
const signature = $input.first().json.headers['x-razorpay-signature'] || '';
const payload = JSON.stringify($input.first().json.body);

const expectedSignature = crypto
  .createHmac('sha256', webhookSecret)
  .update(payload)
  .digest('hex');

const isValid = signature === expectedSignature;

return {
  json: {
    event: $input.first().json.body.event,
    payload: $input.first().json.body.payload,
    isValid
  }
};

// Check if payment was captured
const data = $input.first().json;

if (data.event !== 'payment.captured') {
  return { json: { shouldProceed: false, reason: 'Event not payment.captured' } };
}

const payment = data.payload.payment.entity;
const order = data.payload.order.entity;

return {
  json: {
    shouldProceed: true,
    paymentId: payment.id,
    orderId: order.id,
    amount: payment.amount,
    plan: order.notes?.plan,
    shopName: order.notes?.shopName,
    email: order.notes?.email,
    phone: order.notes?.phone
  }
};

// Generate shop slug
const shopName = $input.first().json.shopName || 'shop';
const shopSlug = shopName
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

const tempPassword = 'Billed@' + Math.random().toString(36).slice(2, 10);

return {
  json: {
    ...$input.first().json,
    shopSlug,
    tempPassword,
    siteUrl: `https://${shopSlug}.billed.in`
  }
};

